// ══════════════════════════════════════════════════════════════════════════════
// ⚙️ SCREEN RECORDING VIDEO GENERATOR - CONFIGURATION
// ══════════════════════════════════════════════════════════════════════════════

return [{
  json: {
    // ─────────────────────────────────────────────────────────────────────────
    // 📝 CONTENT SETTINGS
    // ─────────────────────────────────────────────────────────────────────────
    topic: "How AI is transforming content creation, opening up opportunities for personalization and scale",
    intention: "informative",                            // Options: informative, lead_generation, disruption
    brand_name: "YOUR_BRAND_NAME",
    target_audience: "sales teams and marketers",
    trending_hashtags: "#AIvideo #ContentCreation #VideoMarketing #AItools",

    // ─────────────────────────────────────────────────────────────────────────
    // 🎨 SLIDE STYLE
    // ─────────────────────────────────────────────────────────────────────────
    // Options:
    //   - dark_professional: Dark gradients, white text, sleek look
    //   - light_modern: Light backgrounds, dark text, clean
    //   - vibrant_colorful: Bold colors, energetic, eye-catching
    //   - minimalist: Lots of whitespace, simple, elegant
    //   - tech_corporate: Blue tones, geometric shapes, professional
    slide_style: "vibrant_colorful",

    // ─────────────────────────────────────────────────────────────────────────
    // 🎥 VIDEO SETTINGS
    // ─────────────────────────────────────────────────────────────────────────
    video_resolution: "720p",                           // VEED only supports 720p
    // num_slides is now calculated automatically based on script length
    // Target: 1 slide per 5-7 seconds of audio
    seconds_per_slide: 6,                                // How long each slide shows (affects slide count)

    // ─────────────────────────────────────────────────────────────────────────
    // 🖼️ BACKGROUND (Optional)
    // ─────────────────────────────────────────────────────────────────────────
    // Option 1: Gradient colors array e.g. ["#ff6b6b", "#feca57", "#48dbfb"]
    // Option 2: Image URL string e.g. "https://example.com/background.jpg"
    // Option 3: Empty string "" for no background (full bleed layout)
    background: "",

    // ─────────────────────────────────────────────────────────────────────────
    // 🔑 API KEYS (Required)
    // ─────────────────────────────────────────────────────────────────────────
    anthropic_api_key: "YOUR_ANTHROPIC_API_KEY",
    openai_api_key: "YOUR_OPENAI_API_KEY",
    elevenlabs_api_key: "YOUR_ELEVENLABS_API_KEY",
    creatomate_api_key: "YOUR_CREATOMATE_API_KEY",
    fal_api_key: "YOUR_FAL_API_KEY",

    // ─────────────────────────────────────────────────────────────────────────
    // 🎤 VOICE SELECTION
    // ─────────────────────────────────────────────────────────────────────────
    // Options: cristina (Spanish female), enrique (Spanish male),
    //          susie (English female), jeff (English male),
    //          custom (set your voice ID in Parse node)
    voice_selection: "susie",

    // ─────────────────────────────────────────────────────────────────────────
    // 🎨 AVATAR OPTIONS (Optional)
    // ─────────────────────────────────────────────────────────────────────────
    // Leave both empty for AI-generated avatar
    custom_avatar_description: "",                       // e.g., "a woman in her 30s with casual clothing"
    custom_avatar_image_url: "",                         // Direct URL to an image (publicly accessible)

    // ─────────────────────────────────────────────────────────────────────────
    // 📝 CUSTOM SCRIPT (Optional)
    // ─────────────────────────────────────────────────────────────────────────
    custom_script: ""                                    // Your own script (leave empty for AI-generated)
  }
}];

const config = $input.first().json;

// Slide style definitions with enhanced professional design guidance
const slideStyles = {
  "dark_professional": {
    background: "rich dark gradient (deep navy #0a1628 to charcoal #1a1a2e, or midnight purple #16213e to black)",
    text_color: "crisp white (#ffffff) or soft off-white (#f8f9fa) text, bold modern sans-serif (Inter, SF Pro, or Montserrat style)",
    accent: "subtle neon accents (electric blue #00d4ff or soft purple #a855f7), thin glowing lines, minimal geometric shapes",
    mood: "premium, sophisticated, high-end tech keynote aesthetic like Apple or Stripe presentations",
    layout: "generous whitespace, text positioned with intentional asymmetry, clean visual hierarchy"
  },
  "light_modern": {
    background: "clean white (#ffffff) or warm off-white (#fafafa) with subtle texture or grain",
    text_color: "rich charcoal (#1a1a1a) or dark gray (#374151) text, elegant sans-serif typography",
    accent: "soft pastel accents (blush pink #fecaca, sage green #d1fae5, or sky blue #bae6fd), thin hairlines",
    mood: "airy, minimal, Notion or Linear-style design, sophisticated simplicity",
    layout: "bold use of negative space, text breathing room, modern asymmetric composition"
  },
  "vibrant_colorful": {
    background: "bold gradient mesh (coral #ff6b6b to magenta #f472b6, or cyan #22d3ee to violet #8b5cf6)",
    text_color: "bold white text with subtle drop shadow for contrast, thick modern typeface",
    accent: "organic blob shapes, floating particles, playful geometric elements",
    mood: "energetic, social-media native, Canva Pro or Instagram aesthetic, eye-catching",
    layout: "dynamic compositions, overlapping elements, bold text placements"
  },
  "minimalist": {
    background: "pure solid color (warm cream #fef3c7, soft sage #ecfdf5, or clean white #ffffff)",
    text_color: "black (#000000) or near-black (#111827) text, generous letter-spacing, refined serif or clean sans",
    accent: "single thin rule line, small punctuation mark, or subtle brand color dot",
    mood: "ultra-refined, editorial, Pitch.com or premium agency deck style",
    layout: "extreme whitespace, single focal point, typography as art"
  },
  "tech_corporate": {
    background: "professional blue gradient (#1e3a5f to #0f172a) with subtle grid pattern or data visualization hints",
    text_color: "white or light blue (#e0f2fe) text, clean professional typeface",
    accent: "geometric shapes, circuit-like patterns, subtle glow effects, data viz elements",
    mood: "trustworthy, enterprise-grade, McKinsey or Accenture presentation quality",
    layout: "structured grid-based composition, clear information hierarchy"
  }
};

const selectedStyle = slideStyles[config.slide_style] || slideStyles.dark_professional;
const secondsPerSlide = config.seconds_per_slide || 6;

const hasCustomAvatar = config.custom_avatar_description && config.custom_avatar_description.trim() !== '';
const hasCustomAvatarUrl = config.custom_avatar_image_url && config.custom_avatar_image_url.trim() !== '';
const hasCustomScript = config.custom_script && config.custom_script.trim() !== '';

// Calculate number of slides based on custom script length if provided
let estimatedSlides = 5; // default
if (hasCustomScript) {
  const wordCount = config.custom_script.trim().split(/\s+/).length;
  const estimatedDuration = Math.ceil(wordCount / 2.5); // ~2.5 words per second
  estimatedSlides = Math.max(3, Math.min(8, Math.ceil(estimatedDuration / secondsPerSlide)));
}

const intentionGuides = {
  "informative": "Focus on educating the viewer. Provide genuine value and actionable insights. Build trust through expertise.",
  "lead_generation": "Create curiosity and desire. Include a soft call-to-action. Make them want to learn more.",
  "disruption": "Challenge conventional thinking. Be bold and provocative. Stand out from the noise."
};

// Build dynamic task instructions
let taskInstructions = '';

if (!hasCustomScript) {
  taskInstructions = `### 1. VOICEOVER SCRIPT
Write an engaging, punchy script (25-40 seconds when spoken, approximately 60-100 words) that:
- Opens with an attention-grabbing hook (problem or bold statement)
- Delivers 2-3 key value points in conversational tone
- Is optimized for text-to-speech (natural phrasing, no complex words)
- Builds momentum toward the end
- Ends with a memorable closing line or soft CTA\n\n`;
}

taskInstructions += `### ${hasCustomScript ? '1' : '2'}. SLIDE IMAGE PROMPTS
Create ${hasCustomScript ? estimatedSlides : '5-7'} slides that sync perfectly with the script flow. Each slide should:
- Support exactly one key moment/phrase from the script
- Display 2-4 words maximum as the headline (think billboard, not paragraph)
- Be timed so slides transition naturally with the spoken content\n\n`;

if (!hasCustomAvatarUrl && !hasCustomAvatar) {
  taskInstructions += `### ${hasCustomScript ? '2' : '3'}. AVATAR IMAGE PROMPT
Create a prompt for a photorealistic presenter:
- Head and shoulders framing, direct eye contact with camera
- Professional but approachable, age 25-40
- Confident, friendly expression
- Simple/neutral background\n\n`;
}

taskInstructions += `### ${hasCustomScript && (hasCustomAvatarUrl || hasCustomAvatar) ? '2' : hasCustomScript ? '3' : (hasCustomAvatarUrl || hasCustomAvatar) ? '3' : '4'}. CAPTION
Write a social media caption (under 150 chars) + include the hashtags.`;

// Build response format
let formatObj = {};
if (!hasCustomScript) formatObj.audio_script = "full voiceover script here";
formatObj.slides = [
  { slide_number: 1, image_prompt: "detailed prompt...", display_text: "HEADLINE" },
  { slide_number: 2, image_prompt: "...", display_text: "..." }
];
if (!hasCustomAvatarUrl && !hasCustomAvatar) formatObj.avatar_prompt = "detailed avatar prompt";
formatObj.caption = "caption with hashtags";
formatObj.content_theme = "2-3 word theme";
formatObj.language = "en or es";

const responseFormat = JSON.stringify(formatObj, null, 2).replace(/\n/g, '\\n');

const prompt = `You are a world-class presentation designer who creates slides that rival Pitch.com, Apple Keynotes, and top-tier agency decks.

## CONTENT BRIEF:
- Topic: ${config.topic}
- Brand: ${config.brand_name}
- Target Audience: ${config.target_audience}
- Content Intention: ${config.intention.toUpperCase()}
- Hashtags: ${config.trending_hashtags}
${hasCustomScript ? `- CUSTOM SCRIPT PROVIDED: "${config.custom_script}"` : ''}
${hasCustomAvatar ? `- CUSTOM AVATAR DESCRIPTION: ${config.custom_avatar_description}` : ''}
${hasCustomAvatarUrl ? `- CUSTOM AVATAR IMAGE PROVIDED (no avatar prompt needed)` : ''}

## INTENTION GUIDE:
${intentionGuides[config.intention] || intentionGuides.informative}

## SLIDE DESIGN SYSTEM (CRITICAL):
You are creating prompts for an AI image generator. Each slide must feel like it belongs in a $50,000 pitch deck.

**Visual Style:**
- Background: ${selectedStyle.background}
- Typography: ${selectedStyle.text_color}
- Accents: ${selectedStyle.accent}
- Mood: ${selectedStyle.mood}
- Layout: ${selectedStyle.layout}

**Design Principles:**
1. LESS IS MORE: Maximum 2-4 words per slide, huge and bold
2. VISUAL HIERARCHY: One clear focal point per slide
3. BREATHING ROOM: Generous margins and whitespace
4. CONSISTENCY: Same visual language across all slides
5. IMPACT: Each slide should work as a standalone image

## YOUR TASK:
${taskInstructions}

## CRITICAL REQUIREMENTS FOR IMAGE PROMPTS:
Every slide prompt MUST include:
1. "16:9 aspect ratio, 1920x1080, landscape orientation" (exact words)
2. Specific hex color codes for backgrounds and accents
3. Exact text to display in quotes (e.g., "THINK BIGGER")
4. Text styling: "large bold centered sans-serif text"
5. Composition details: where elements are positioned
6. Quality markers: "high resolution, professional design, premium aesthetic"

Example prompt format:
"16:9 aspect ratio, 1920x1080, landscape orientation. Rich gradient background from deep navy #0a1628 to charcoal #1a1a2e. Large bold white centered sans-serif text reading 'THINK BIGGER' with subtle electric blue #00d4ff glow effect. Generous whitespace, minimal composition, premium tech keynote aesthetic, high resolution."

## OUTPUT FORMAT:
Respond ONLY with valid JSON (no markdown, no code blocks):
${responseFormat}`;

return [{
  json: {
    ...config,
    claude_prompt: prompt,
    slide_style_config: selectedStyle,
    seconds_per_slide: secondsPerSlide,
    estimated_slides: estimatedSlides,
    has_custom_avatar: hasCustomAvatar,
    has_custom_avatar_url: hasCustomAvatarUrl,
    has_custom_script: hasCustomScript
  }
}];

const item = $input.first();
const claudeResponse = item.json;
const config = $('🧠 Build Claude Prompt').item.json;

let responseText = '';
if (claudeResponse.content && claudeResponse.content[0]) {
  responseText = claudeResponse.content[0].text;
}

let parsed = {};
try {
  let cleanText = responseText.trim();
  if (cleanText.startsWith('```json')) {
    cleanText = cleanText.replace(/```json\n?/, '').replace(/\n?```$/, '');
  } else if (cleanText.startsWith('```')) {
    cleanText = cleanText.replace(/```\n?/, '').replace(/\n?```$/, '');
  }
  parsed = JSON.parse(cleanText.trim());
} catch (e) {
  // Fallback content
  const defaultSlides = [];
  const slideTexts = ["AI REVOLUTION", "FASTER RESULTS", "SMARTER WORK", "YOUR EDGE", "START NOW"];
  for (let i = 0; i < 5; i++) {
    defaultSlides.push({
      slide_number: i + 1,
      image_prompt: `16:9 aspect ratio, 1920x1080, landscape orientation. Rich gradient background from deep navy #0a1628 to charcoal #1a1a2e. Large bold white centered sans-serif text reading "${slideTexts[i]}" with subtle blue glow. Premium tech aesthetic, high resolution.`,
      display_text: slideTexts[i]
    });
  }

  parsed = {
    audio_script: "AI is revolutionizing how we work. What once took hours now takes minutes. From content to analysis, the possibilities are endless. Are you ready to embrace the future?",
    slides: defaultSlides,
    avatar_prompt: "Photorealistic portrait of a confident tech professional in their early 30s, wearing smart casual clothing, warm friendly smile, direct eye contact, soft neutral background, high quality portrait photography",
    caption: "AI is changing everything. Are you ready? #AIvideo #ContentCreation",
    content_theme: "AI Transformation",
    language: "en"
  };
}

// Voice selection
const voiceMap = {
  "cristina": "CaJslL1xziwefCeTNzHv",
  "enrique": "iDEmt5MnqUotdwCIVplo",
  "susie": "gPe4h2IS1C7XHbnizzFa",
  "jeff": "gs0tAILXbY5DNrJrsM6F",
  "custom": "YOUR_VOICE_CLONE_ID"
};

const voiceSelection = (config.voice_selection || 'susie').toLowerCase().trim();
const selectedVoiceId = voiceMap[voiceSelection] || voiceMap['susie'];

let language = (parsed.language || 'en').toLowerCase().substring(0, 2);
if (voiceSelection === 'cristina' || voiceSelection === 'enrique') {
  language = 'es';
}

// Handle avatar prompt
let avatarPrompt = '';
if (config.has_custom_avatar_url) {
  avatarPrompt = '';
} else if (config.has_custom_avatar) {
  avatarPrompt = `Photorealistic portrait photo of ${config.custom_avatar_description}. Head and shoulders framing, looking directly at camera, natural confident expression, high quality, portrait orientation, professional lighting, 4K quality.`;
} else if (parsed.avatar_prompt) {
  avatarPrompt = parsed.avatar_prompt;
} else {
  avatarPrompt = "Photorealistic portrait of a confident professional in their early 30s, smart casual attire, warm smile, direct eye contact, soft neutral background, high quality portrait";
}

// Handle script
let finalScript = '';
if (config.has_custom_script) {
  finalScript = config.custom_script.trim();
} else if (parsed.audio_script) {
  finalScript = parsed.audio_script;
} else {
  finalScript = "AI is revolutionizing content creation. What once took hours now takes minutes. Are you ready to embrace the future?";
}

// Calculate estimated duration from script (approx 2.5 words per second)
const wordCount = finalScript.split(/\s+/).length;
const estimatedDuration = Math.ceil(wordCount / 2.5) + 2; // Add 2 seconds buffer
const secondsPerSlide = config.seconds_per_slide || 6;

// Get slides from Claude response - use all slides it generated
let slides = parsed.slides || [];

// If no slides, create defaults based on estimated duration
if (slides.length === 0) {
  const numSlides = Math.max(3, Math.ceil(estimatedDuration / secondsPerSlide));
  const defaultTexts = ["TRANSFORM", "ACCELERATE", "INNOVATE", "SCALE", "SUCCEED", "LEAD", "GROW", "WIN"];
  for (let i = 0; i < numSlides; i++) {
    slides.push({
      slide_number: i + 1,
      image_prompt: `16:9 aspect ratio, 1920x1080, landscape orientation. Rich gradient background from deep navy #0a1628 to charcoal #1a1a2e. Large bold white centered sans-serif text reading "${defaultTexts[i % defaultTexts.length]}" with subtle blue glow. Premium aesthetic.`,
      display_text: defaultTexts[i % defaultTexts.length]
    });
  }
}

const numSlides = slides.length;
const durationPerSlide = estimatedDuration / numSlides;

// Determine background type
const bgConfig = config.background;
let backgroundType = 'none';
let backgroundValue = null;

if (bgConfig) {
  if (typeof bgConfig === 'string' && bgConfig.trim() !== '') {
    // It's a URL
    backgroundType = 'url';
    backgroundValue = bgConfig.trim();
  } else if (Array.isArray(bgConfig) && bgConfig.length > 0) {
    // It's a gradient array
    backgroundType = 'gradient';
    backgroundValue = bgConfig;
  }
}

return [{
  json: {
    // Config passthrough
    topic: config.topic,
    intention: config.intention,
    brand_name: config.brand_name,
    target_audience: config.target_audience,
    trending_hashtags: config.trending_hashtags,
    slide_style: config.slide_style,
    video_resolution: config.video_resolution,

    // Calculated values
    num_slides: numSlides,
    estimated_duration: estimatedDuration,
    duration_per_slide: durationPerSlide,
    script_word_count: wordCount,

    // API keys
    anthropic_api_key: config.anthropic_api_key,
    openai_api_key: config.openai_api_key,
    elevenlabs_api_key: config.elevenlabs_api_key,
    creatomate_api_key: config.creatomate_api_key,
    fal_api_key: config.fal_api_key,

    // Background config
    background_type: backgroundType,
    background_value: backgroundValue,

    // Generated content
    script_audio: finalScript,
    avatar_prompt: avatarPrompt,
    slides: slides,
    caption: parsed.caption || "Check out this AI-generated video! #AIvideo #ContentCreation",
    content_theme: parsed.content_theme || "AI Innovation",
    language: language,
    voice_selection: voiceSelection,
    voice_id: selectedVoiceId,

    // Avatar handling flags
    has_custom_avatar_url: config.has_custom_avatar_url,
    custom_avatar_image_url: config.custom_avatar_image_url || ''
  }
}];

// Split into two parallel flows:
// Flow A: Avatar (image → audio → VEED)
// Flow B: Slides (Nanobanana)

const data = $input.first().json;

return [
  {
    json: {
      ...data,
      flow: 'avatar'
    }
  },
  {
    json: {
      ...data,
      flow: 'slides'
    }
  }
];

const data = $input.first().json;
return [{
  json: {
    ...data,
    avatar_image_url: data.custom_avatar_image_url
  }
}];

const item = $input.first();
const imageResponse = item.json;
const previousData = $('🖼️ Has Custom Avatar URL?').item.json;

let imageBase64 = '';
if (imageResponse.data && imageResponse.data[0] && imageResponse.data[0].b64_json) {
  imageBase64 = imageResponse.data[0].b64_json;
}

if (!imageBase64) {
  throw new Error('No base64 image data received from OpenAI');
}

return [{
  json: {
    ...previousData
  },
  binary: {
    avatar_image: {
      data: imageBase64,
      mimeType: 'image/png',
      fileName: 'avatar.png'
    }
  }
}];

const uploadResponse = $input.first().json;
const previousData = $('📸 Extract Avatar Image').item.json;

const avatarImageUrl = uploadResponse.data.url.replace(
  /^http:\/\/tmpfiles\.org\/(\d+)\/(.*)$/i,
  'https://tmpfiles.org/dl/$1/$2'
);

return [{
  json: {
    ...previousData,
    avatar_image_url: avatarImageUrl
  }
}];

// Get previous data from whichever avatar path we came from
let previousData;
try {
  previousData = $('💾 Store Avatar URL').item.json;
} catch (e) {
  try {
    previousData = $('📸 Use Custom Avatar URL').item.json;
  } catch (e2) {
    previousData = $('🖼️ Has Custom Avatar URL?').item.json;
  }
}

return items.map(item => {
  const b = item.binary?.audio;
  if (!b) return item;

  item.json = { ...previousData };
  item.binary.audio_mp3 = {
    ...b,
    fileName: 'voiceover.mp3',
    mimeType: 'audio/mpeg'
  };

  return item;
});

const uploadResponse = $input.first().json;
const previousData = $('🎵 Convert Audio').item.json;

const audioUrl = uploadResponse.data.url.replace(
  /^http:\/\/tmpfiles\.org\/(\d+)\/(.*)$/i,
  'https://tmpfiles.org/dl/$1/$2'
);

return [{
  json: {
    ...previousData,
    audio_url: audioUrl
  }
}];

const veedResult = $input.first().json;
const previousData = $('💾 Store Audio URL').item.json;

let videoUrl = '';
if (veedResult.video && veedResult.video.url) {
  videoUrl = veedResult.video.url;
} else if (veedResult.output && veedResult.output.video_url) {
  videoUrl = veedResult.output.video_url;
} else if (veedResult.videoUrl) {
  videoUrl = veedResult.videoUrl;
} else if (veedResult.url) {
  videoUrl = veedResult.url;
}

return [{
  json: {
    ...previousData,
    avatar_video_url: videoUrl,
    asset_type: 'avatar_video'
  }
}];

// Expand slides into individual items for parallel generation
const data = $input.first().json;
const slides = data.slides || [];

return slides.map((slide, index) => ({
  json: {
    ...data,
    current_slide: slide,
    slide_index: index
  }
}));

// Process ALL FAL responses and extract URLs
const items = $input.all();
const expandedItems = $('📑 Expand Slides').all();

const results = [];

for (let i = 0; i < items.length; i++) {
  const falResponse = items[i].json;
  const slideData = expandedItems[i]?.json || {};

  // FAL returns the image URL in the response
  let slideImageUrl = '';

  if (falResponse.images && falResponse.images[0]) {
    slideImageUrl = falResponse.images[0].url;
  } else if (falResponse.image && falResponse.image.url) {
    slideImageUrl = falResponse.image.url;
  } else if (falResponse.output && falResponse.output[0]) {
    slideImageUrl = falResponse.output[0];
  }

  if (!slideImageUrl) {
    throw new Error('No image URL received from FAL for slide ' + i + '. Response: ' + JSON.stringify(falResponse).substring(0, 500));
  }

  results.push({
    json: {
      slide_index: slideData.slide_index,
      slide_image_url: slideImageUrl,
      slide_data: slideData.current_slide,
      duration_seconds: slideData.current_slide?.duration_seconds || slideData.seconds_per_slide || 9,
      asset_type: 'slide'
    }
  });
}

return results;

// Process aggregated slides into final format
const aggregatedData = $input.first().json;
const allSlides = aggregatedData.all_slides_data || [];

// Sort slides by index
const sortedSlides = allSlides
  .sort((a, b) => (a.slide_index || 0) - (b.slide_index || 0))
  .map(slide => ({
    slide_index: slide.slide_index,
    slide_image_url: slide.slide_image_url,
    slide_data: slide.slide_data,
    duration_seconds: slide.duration_seconds
  }));

return [{
  json: {
    slides_with_urls: sortedSlides,
    asset_type: 'all_slides'
  }
}];

// Combine avatar video and slides for Creatomate RenderScript
const items = $input.all();

let avatarVideoUrl = '';
let slidesWithUrls = [];
let baseData = {};

for (const item of items) {
  const data = item.json;

  if (data.avatar_video_url && data.avatar_video_url !== '') {
    avatarVideoUrl = data.avatar_video_url;
    baseData = data;
  }

  if (data.slides_with_urls && Array.isArray(data.slides_with_urls) && data.slides_with_urls.length > 0) {
    slidesWithUrls = data.slides_with_urls;
  }
}

// Use estimated_duration from script calculation
const totalDuration = baseData.estimated_duration || 30;
const numSlides = slidesWithUrls.length || 1;
const durationPerSlide = totalDuration / numSlides;

// Build slide elements
const slideElements = slidesWithUrls.map((slide, index) => {
  const element = {
    type: 'image',
    track: 1,
    source: slide.slide_image_url,
    duration: durationPerSlide,
    fit: 'cover'
  };

  if (index > 0) {
    element.animations = [
      {
        time: 0,
        duration: 0.5,
        transition: true,
        type: 'fade'
      }
    ];
  }

  return element;
});

// Build the complete Creatomate elements array based on background type
const creatomateElements = [];
const backgroundType = baseData.background_type || 'none';
const backgroundValue = baseData.background_value;
const hasBackground = backgroundType !== 'none';

if (backgroundType === 'gradient' && Array.isArray(backgroundValue)) {
  // Gradient background
  const colors = backgroundValue;
  const colorStops = [];
  for (let i = 0; i < Math.min(colors.length, 5); i++) {
    colorStops.push({
      offset: `${Math.round((i / (Math.min(colors.length, 5) - 1)) * 100)}%`,
      color: colors[i]
    });
  }

  creatomateElements.push({
    type: 'shape',
    track: 1,
    time: 0,
    duration: totalDuration,
    width: '100%',
    height: '100%',
    fill_color: colorStops,
    fill_mode: 'linear',
    fill_x0: '0%',
    fill_y0: '0%',
    fill_x1: '100%',
    fill_y1: '100%'
  });
} else if (backgroundType === 'url' && backgroundValue) {
  // Image URL background
  creatomateElements.push({
    type: 'image',
    track: 1,
    time: 0,
    duration: totalDuration,
    source: backgroundValue,
    width: '100%',
    height: '100%',
    fit: 'cover'
  });
}

if (hasBackground) {
  // With background - add margins and rounded corners
  creatomateElements.push({
    type: 'composition',
    track: 2,
    time: 0,
    duration: totalDuration,
    x: '2%',
    y: '50%',
    width: '74%',
    height: '96%',
    x_anchor: '0%',
    y_anchor: '50%',
    border_radius: '12px',
    clip: true,
    elements: slideElements
  });

  creatomateElements.push({
    type: 'video',
    track: 3,
    time: 0,
    source: avatarVideoUrl,
    x: '98%',
    y: '50%',
    width: '20%',
    height: '96%',
    x_anchor: '100%',
    y_anchor: '50%',
    border_radius: '12px',
    fit: 'cover'
  });
} else {
  // No background - full bleed layout
  creatomateElements.push({
    type: 'composition',
    track: 1,
    time: 0,
    duration: totalDuration,
    x: '0%',
    y: '50%',
    width: '78%',
    height: '100%',
    x_anchor: '0%',
    y_anchor: '50%',
    clip: true,
    elements: slideElements
  });

  creatomateElements.push({
    type: 'video',
    track: 2,
    time: 0,
    source: avatarVideoUrl,
    x: '100%',
    y: '50%',
    width: '22%',
    height: '100%',
    x_anchor: '100%',
    y_anchor: '50%',
    fit: 'cover'
  });
}

return [{
  json: {
    ...baseData,
    avatar_video_url: avatarVideoUrl,
    slides_with_urls: slidesWithUrls,
    slide_elements: slideElements,
    creatomate_elements: creatomateElements,
    total_duration: totalDuration,
    duration_per_slide: durationPerSlide,
    num_slides: numSlides,
    has_background: hasBackground,
    background_type: backgroundType
  }
}];

